head.script:
scwin.regId = $c.data.getMemInfo("userID");
scwin.firstDay = $c.date.getServerDateTime("yyyyMMdd").substring(0, 6) + "01";
scwin.today = $c.date.getServerDateTime("yyyyMMdd");

scwin.onpageload = function () {
    let codeOptions = [
        { grpCd: "OP194", compID: "acb_expimpClsCd" }, //수출입 구분
        { grpCd: "ZZ210", compID: "gr_selfInoutList2:eqKndCd" }
    ];

    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function () {
    ed_arrvlportDtmFrom.setValue(scwin.firstDay);
    ed_arrvlportDtmTo.setValue(scwin.today);

};

//-------------------------------------------------------------------------
//날짜 스트링에 일수 더하기 or 빼는 함수
//-------------------------------------------------------------------------
scwin.updateDate = function (dateStr, minuteOffset) {
    let y = parseInt(dateStr.substring(0, 4), 10);
    let m = parseInt(dateStr.substring(4, 6), 10) - 1;
    let d = parseInt(dateStr.substring(6, 8), 10);
    let hh = parseInt(dateStr.substring(8, 10), 10);
    let mm = parseInt(dateStr.substring(10, 12), 10);

    let dt = new Date(y, m, d, hh, mm + parseInt(minuteOffset, 10));

    return scwin.dateToStr(dt);
};

scwin.dateToStr = function (date) {
    let year = date.getFullYear();
    let month = String(date.getMonth() + 1).padStart(2, "0");
    let day = String(date.getDate()).padStart(2, "0");
    let hour = String(date.getHours()).padStart(2, "0");
    let minute = String(date.getMinutes()).padStart(2, "0");

    return `${year}${month}${day}${hour}${minute}`;
};

scwin.getOffsetDate = function (sDate1, sDate2) {
    // sDate는 YYYYMMDDHHmm 또는 YYYYMMDD 형태 가능
    const d1 = scwin.parseDate(sDate1);
    const d2 = scwin.parseDate(sDate2);

    // 1일 = 86400000ms
    const diffMs = d1.getTime() - d2.getTime();
    const diffDays = diffMs / (1000 * 60 * 60 * 24);

    return Math.max(0, Math.ceil(diffDays));  // 음수면 0 처리
};

scwin.parseDate = function (sDate) {
    let year = sDate.substring(0, 4);
    let month = sDate.substring(4, 6);
    let day = sDate.substring(6, 8);
    let hours = sDate.substring(8, 10);
    let minutes = sDate.substring(10, 12);
    let seconds = sDate.substring(12, 14);

    let date = new Date(year, month, day, hours, minutes, seconds, 0);

    return date;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await $c.gus.cfValidate([tbl_search])) return;

    if (ed_arrvlportDtmFrom.getValue() > ed_arrvlportDtmTo.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);	//시작일자가 종료일자 이전이어야 합니다.
        ed_arrvlportDtmFrom.focus();
        return;
    }

    $c.sbm.execute(sbm_ret);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (!ds_master.getModifiedIndex().length) return;

    let chkCount = 0;

    for (let i = 0; i < ds_master.getRowCount(); i++) {
        let rowJson = ds_master.getRowJSON(i);

        if (rowJson.inOdrChk == 1 || rowJson.outOdrChk == 1) {		// 체크 박스 선택 했을 때 
            chkCount++;
        }
    }

    if (chkCount == 0) {
        await $c.gus.cfAlertMsg("선택된 건이 하나도 없습니다.\n확인해 주십시오.");
        return;
    }

    if (!await scwin.f_Check()) return;

    let ret = await $c.win.confirm("저장하시겠습니까?");

    if (!ret) return;

    $c.sbm.execute(sbm_save);
};

//-------------------------------------------------------------------------
// 화면 입력 값 유효성 체크 ( 입력값 셋팅 : 모선. 항차 셋팅 ) 
//-------------------------------------------------------------------------
scwin.f_Check = async function () {
    // DPCT 냉동 컨테이너 매출 등록 유효성 체크 
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        let rowJson = ds_master.getRowJSON(i);

        if (rowJson.inOdrChk == 1 || rowJson.outOdrChk == 1) {		//  체크 박스 선택 했을 때 
            // PLUG IN OR PLUG OUT  필수 (둘다 없을 경우)
            if (rowJson.pluginDt == "" && rowJson.plugoutDt == "") {
                await $c.gus.cfAlertMsg((i + 1) + "번째 항의 PLUG IN과 PLUG OUT은 필수 입력 사항입니다.\n자동 선택 해제 처리 합니다.");
                ds_master.setCellData(i, "inOdrChk", "0");
                ds_master.setCellData(i, "outOdrChk", "0");

                return false;
            }

            // PLUG IN만 있을 경우, 반출오더번호 NULL로 셋팅(화주매출 생성 안되도록)
            if (rowJson.pluginDt != "" && rowJson.plugoutDt == "") {
                ds_master.setCellData(i, "outOdrNo", "");
            }

            // PLUG OUT만 있을 경우, 반입오더번호 NULL로 셋팅(선사매출 생성 안되도록)
            if (rowJson.pluginDt == "" && rowJson.plugoutDt != "") {
                ds_master.setCellData(i, "inOdrNo", "");
            }
        }

        if (rowJson.inOdrChk == 1) {		//  체크 박스 선택 했을 때 
            //반입오더 매출 확정구분코드가 "1"보다 클경우("미확정"이 아닐경우) 수정불가능 체크 해제
            if (rowJson.inOdrDcsnClsCd > 1) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 항의 반입오더 매출이 미확정이 아닙니다.\n자동 선택 해제 처리 합니다.");
                ds_master.setCellData(i, "inOdrChk", "0");

                return false;
            }
        }

        if (rowJson.outOdrChk == 1) {		//  체크 박스 선택 했을 때 
            //반출오더 매출 확정구분코드가 "1"보다 클경우("미확정"이 아닐경우) 수정불가능 체크 해제
            if (rowJson.outOdrDcsnClsCd > 1) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 항의 반출오더 매출이 미확정이 아닙니다.\n자동 선택 해제 처리 합니다.");
                ds_master.setCellData(i, "outOdrChk", "0");

                return false;
            }
        }
    }

    return true;
};

//-------------------------------------------------------------------------
// 필드 클리어
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);
};

scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // Line Info;
            udc_comCodeLine.cfCommonPopUp(function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm);
            }	// XML상의 SELECT ID	
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , "2"					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "LINE조회,LINE코드,LINE명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }

};

scwin.f_excel = function () {
    let options = {
        fileName: "DPCT냉동컨테이너조회" + ".xlsx",
        sheetName: "DPCT 냉동컨테이너"
    }

    $c.data.downloadGridViewExcel(grd_master, options);
};

//-------------------------------------------------------------------------
// 화물 추적 링크 
//-------------------------------------------------------------------------
scwin.f_cntrSearch = function () {
    let strOrderDetailUrl = "ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml";
    let strOrderDetailTitle = "컨테이너  화물추적";

    // 선택된 오더 정보 : 오더번호 , flag
    let v_cntrNo = ds_master.getCellData(ds_master.getRowPosition(), "cntrNo");

    let paramObj = {
        cntrNo: v_cntrNo
    }

    $c.win.openMenu(strOrderDetailTitle, strOrderDetailUrl, "as_102_01_02b.xml", paramObj, null);
}

scwin.sbm_ret_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    if (ds_master.getRowCount() == 0) {
        $c.gus.cfAlertMsg("[DPCT 냉동 컨테이너 조회 ] " + MSG_CM_ERR_003);
    }

    totalRows.setValue(ds_master.getRowCount());
};

scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};

scwin.grd_master_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.olddata = value;
};

scwin.grd_master_onafteredit = async function (rowIndex, columnIndex, value) {
    let colid = ds_master.getColumnID(columnIndex);
    let rowJson = ds_master.getRowJSON(rowIndex);

    if (colid == "plugoutDt" || colid == "pluginDt") {
        // 반입오더 매출일수
        if (!(rowJson.pluginDt == "") && !(rowJson.applyDt == "")) {
            ds_master.setCellData(rowIndex, "inOdrSellDay",
                scwin.getOffsetDate(rowJson.applyDt + "00",
                    rowJson.pluginDt + "00"));
        }

        // 반출오더 매출일수
        if (!(rowJson.plugoutDt == "") && !(rowJson.applyDt == "")) {
            ds_master.setCellData(rowIndex, "outOdrSellDay",
                scwin.getOffsetDate(rowJson.plugoutDt + "00",
                    rowJson.applyDt + "00"));
        }

        // 총 장치일수(PLUGOUT - PLUGIN)
        if (!(rowJson.pluginDt == "") && !(rowJson.plugoutDt == "")) {
            ds_master.setCellData(rowIndex, "totDay",
                scwin.getOffsetDate(rowJson.plugoutDt + "00",
                    rowJson.pluginDt + "00"));
        }

        // PLUGIN이 수정되었을 경우
        if (colid == "pluginDt") {
            if (rowJson.pluginDt != scwin.olddata) {
                ds_master.setCellData(rowIndex, "pluginModId", scwin.regId);
            }
        }

        // PLUGOUT이 수정되었을 경우
        if (colid == "plugoutDt") {
            if (rowJson.plugoutDt != scwin.olddata) {
                ds_master.setCellData(rowIndex, "plugoutModId", scwin.regId);
            }
        }
    }

    // 적용일시 수정시
    if (colid == "applyDt") {
        // 반입/반출 미확정 체크
        if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
            await $c.gus.cfAlertMsg((rowIndex + 1) + "번째 항의 적용일시는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
            ds_master.setCellData(rowIndex, "applyDt", scwin.olddata);
            return true;
        }

        // 적용일시 범위 체크 (plugin < apply < plugout)
        if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
            if ((rowJson.applyDt > rowJson.plugoutDt) || (rowJson.applyDt < rowJson.pluginDt)) {
                await $c.gus.cfAlertMsg("적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
                ds_master.setCellData(rowIndex, "applyDt", scwin.olddata);
                return true;
            }
        }

        // 반입오더 매출일수(적용일시 - PLUGIN)
        if (!(rowJson.pluginDt == "")) {
            if (rowJson.pluginDt == rowJson.applyDt) {
                ds_master.setCellData(rowIndex, "inOdrSellDay", 0);
            } else {
                ds_master.setCellData(rowIndex, "inOdrSellDay",
                    scwin.getOffsetDate(rowJson.applyDt + "00",
                        rowJson.pluginDt + "00"));
            }
        }

        // 반출오더 매출일수(PLUGOUT - 적용일시)
        if (!(rowJson.plugoutDt == "")) {
            ds_master.setCellData(rowIndex, "outOdrSellDay",
                scwin.getOffsetDate(rowJson.plugoutDt + "00",
                    rowJson.applyDt + "00"));
        }

    }

    // 반입오더 매출일수 수정시
    if (colid == "inOdrSellDay") {
        // 미확정 체크
        if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
            await $c.gus.cfAlertMsg((rowIndex + 1) + "번째 항의 반입오더 매출일수는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
            ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
            return true;
        }

        // 마이너스 입력 체크
        if (rowJson.inOdrSellDay < 0) {
            await $c.gus.cfAlertMsg("반입오더 매출일수를 잘못 입력하셨습니다.");
            ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
            return true;
        }

        // 적용일시 변경
        if (!(rowJson.pluginDt == "")) {

            if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
                if ((rowJson.applyDt > rowJson.plugoutDt) || (rowJson.applyDt < rowJson.pluginDt)) {
                    await $c.gus.cfAlertMsg("적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
                    ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
                    return true;
                }
            }

            if (rowJson.inOdrSellDay == 0) {
                ds_master.setCellData(rowIndex, "applyDt", rowJson.pluginDt);
            } else {
                let minutes = (rowJson.inOdrSellDay * 24 * 60) - 1;

                if (rowJson.plugoutDt != "") {
                    if (scwin.updateDate(rowJson.pluginDt, minutes) > rowJson.plugoutDt) {
                        await $c.gus.cfAlertMsg("반입오더 매출일수를 다시 입력해주세요.");
                        ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
                        return true;
                    }
                }

                ds_master.setCellData(rowIndex, "applyDt", scwin.updateDate(rowJson.pluginDt, minutes));
            }
        }

        // 반출오더 매출일수
        if (!(rowJson.plugoutDt == "") && !(ds_master.getCellData(rowIndex, "applyDt") == "")) {

            if (rowJson.plugoutDt == ds_master.getCellData(rowIndex, "applyDt")) {
                ds_master.setCellData(rowIndex, "outOdrSellDay", 0);
            } else {
                ds_master.setCellData(rowIndex, "outOdrSellDay",
                    scwin.getOffsetDate(rowJson.plugoutDt + "00",
                        ds_master.getCellData(rowIndex, "applyDt") + "00"));
            }
        }
    }

    // 반출오더 매출일수 수정시
    if (colid == "outOdrSellDay") {
        // 반입/반출 미확정일 경우 수정 불가
        if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
            await $c.gus.cfAlertMsg((rowIndex + 1) + "번째 항의 반출오더 매출일수는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
            ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
            return true;
        }

        // 음수 입력 시
        if (rowJson.outOdrSellDay < 0) {
            await $c.gus.cfAlertMsg("반입오더 매출일수를 잘못 입력하셨습니다.");
            ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
            return true;
        }

        // 적용일시 계산 (PLUGOUT 기준)
        if (!(rowJson.plugoutDt == "")) {
            // 적용일시 범위 체크 (plugin < apply < plugout)
            if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
                if ((rowJson.applyDt > rowJson.plugoutDt) || (rowJson.applyDt < rowJson.pluginDt)) {
                    await $c.gus.cfAlertMsg("적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
                    ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
                    return true;
                }
            }

            // 매출일수 0 → 적용일시 = plugoutDt
            if (rowJson.outOdrSellDay == 0) {
                ds_master.setCellData(rowIndex, "applyDt", rowJson.plugoutDt);
            } else {
                let minutes = (rowJson.outOdrSellDay * 24 * 60) - 1;

                // 적용일시가 plugoutDt 이후가 되면 오류
                if (scwin.updateDate(rowJson.plugoutDt, -minutes) > rowJson.plugoutDt) {

                    await $c.gus.cfAlertMsg("반입오더 매출일수를 다시 입력해주세요.");
                    ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
                    return true;
                }

                ds_master.setCellData(rowIndex, "applyDt", scwin.updateDate(rowJson.plugoutDt, -minutes));
            }
        }

        // 반입오더 매출일수 = 적용일시 - PLUGIN
        if (!(rowJson.pluginDt == "") && !(rowJson.applyDt == "")) {
            ds_master.setCellData(rowIndex, "inOdrSellDay",
                scwin.getOffsetDate(rowJson.applyDt + "00", rowJson.pluginDt + "00"));
        }
    }

    if (colid == "applyDt") {
        if (ds_master.getModifiedIndex().length > 0) {
            grd_master.setColumnReadOnly("inOdrSellDay", true);
            grd_master.setColumnReadOnly("outOdrSellDay", true);
        }
    }

    if (colid == "inOdrSellDay") {
        if (ds_master.getModifiedIndex().length > 0) {
            grd_master.setColumnReadOnly("applyDt", true);
            grd_master.setColumnReadOnly("outOdrSellDay", true);
        }
    }

    if (colid == "outOdrSellDay") {
        if (ds_master.getModifiedIndex().length > 0) {
            grd_master.setColumnReadOnly("applyDt", true);
            grd_master.setColumnReadOnly("inOdrSellDay", true);
        }
    }
};

scwin.ds_master_onrowpositionchange = function (info) {
    grd_master.setColumnReadOnly("applyDt", false);
    grd_master.setColumnReadOnly("inOdrSellDay", false);
    grd_master.setColumnReadOnly("outOdrSellDay", false);
};

scwin.grd_master_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    // 화물추적 링크
    if (columnId == "cntrNo") {
        scwin.f_cntrSearch();
    }
};

// 컨테이너번호
scwin.ed_cntrNo_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

// 반입오더번호
scwin.ed_inOdrNo_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

// 반출오더번호
