scwin.customFormatter = function (data, formattedData, rowIndex, colIndex) {
    ds_master.setIgnoreStatus("totBillingDay", true);

    let colId = this.getColumnID(colIndex);

    if (colId == "inOdrSellDay" || colId == "outOdrSellDay") {
        let rowJson = ds_master.getRowJSON(rowIndex);
        let totBillingDay = Number(rowJson.inOdrSellDay) + Number(rowJson.outOdrSellDay);

        ds_master.setCellData(rowIndex, "totBillingDay", totBillingDay);
        return formattedData;
    }
};
